import {
  Box,
  Button,
  Flex,
  Heading,
  Text,
  Modal,
  ModalBody,
  ModalCloseButton,
  ModalContent,
  ModalFooter,
  ModalHeader,
  ModalOverlay,
  Input,
  useToast,
  Divider,
} from "@chakra-ui/react";
import { useEffect, useState } from "react";
import axios from "axios";
import { useParams } from "react-router";
import DynamicSelect from "./DynamicSelect";
import { capitalizeFirstLetter } from "../../Redux/UserReducer/action";
import { showToast } from "../../components/SignUp";

export default function Payment({ isOpen, onClose }) {
  const { id } = useParams();
  const [course, setCourse] = useState({});
  const [input, setInput] = useState("");
  const toast = useToast();

  const token = JSON.parse(localStorage.getItem("user"))?.token || "";
  const baseURL = "http://localhost:8080";

  useEffect(() => {
    axios
      .get(`${baseURL}/courses/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => setCourse(res.data.course))
      .catch(console.log);
  }, []);

  const handlePayment = () => {
    axios
      .post(
        `${baseURL}/users/addCourse/${id}`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      )
      .then((res) => {
        showToast({
          toast,
          message: res?.data?.message,
          color: "green",
        });
        onClose();
      })
      .catch((err) => {
        showToast({
          toast,
          message: err?.response?.data?.error,
          color: "red",
        });
        onClose();
      });
  };

  const isValidUPI = input.includes("@");

  return (
    <Modal isOpen={isOpen} onClose={onClose} isCentered>
      <ModalOverlay />
      <ModalContent borderRadius="lg">
        <ModalHeader fontWeight="bold">Checkout</ModalHeader>
        <ModalCloseButton />

        <ModalBody>
          {/* Course Info */}
          <Box mb={5}>
            <Heading size="sm" mb={2}>
              {capitalizeFirstLetter(course?.title)}
            </Heading>
            <Text fontSize="sm" color="#6a6f73">
              Instructor: {capitalizeFirstLetter(course?.teacher)}
            </Text>
            <Text fontSize="sm" color="#6a6f73">
              {course?.videos?.length || 1} videos included
            </Text>
          </Box>

          <Divider my={4} />

          {/* Billing */}
          <Box mb={5}>
            <Heading size="sm" mb={3}>
              Billing Address
            </Heading>
            <DynamicSelect />
          </Box>

          <Divider my={4} />

          {/* Payment */}
          <Box>
            <Heading size="sm" mb={3}>
              Payment Method
            </Heading>

            <Text fontSize="sm" mb={2}>
              UPI ID
            </Text>

            <Input
              placeholder="example@upi"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              borderRadius="md"
              border="1px solid #d1d7dc"
              _focus={{
                borderColor: "#A435F0",
                boxShadow: "0 0 0 1px #A435F0",
              }}
            />
          </Box>
        </ModalBody>

        <ModalFooter justifyContent="space-between">
          <Text fontWeight="bold">₹{course?.price}</Text>

          <Flex gap={3}>
            <Button variant="outline" onClick={onClose}>
              Cancel
            </Button>

            <Button
              bg="#A435F0"
              color="white"
              _hover={{ bg: "#8710d8" }}
              isDisabled={!isValidUPI}
              onClick={handlePayment}
            >
              Pay Now
            </Button>
          </Flex>
        </ModalFooter>
      </ModalContent>
    </Modal>
  );
}
